import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Table, Button, Alert, Tab, Tabs } from 'react-bootstrap';
import { useAuth } from '../context/AuthContext';

const DebugDashboard = () => {
  const { token, authFetch } = useAuth();
  const [allData, setAllData] = useState(null);
  const [foodData, setFoodData] = useState(null);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadAllData();
    loadFoodData();
  }, []);

  const loadAllData = async () => {
    try {
      const res = await authFetch('/api/debug/data');
      if (res.ok) {
        const data = await res.json();
        setAllData(data);
        console.log('Debug data loaded:', data);
      }
    } catch (err) {
      console.error('Failed to load debug data:', err);
    }
  };

  const refreshData = () => {
    loadAllData();
    loadFoodData();
  };

  const loadFoodData = async () => {
    try {
      const res = await authFetch('/api/debug/foods');
      if (res.ok) {
        const data = await res.json();
        setFoodData(data);
      }
    } catch (err) {
      console.error('Failed to load food data:', err);
    }
  };

  const downloadData = (data, filename) => {
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  if (!token) {
    return (
      <Container className="mt-4">
        <Alert variant="warning">
          Please login to access debug information.
        </Alert>
      </Container>
    );
  }

  if (loading) {
    return (
      <Container className="mt-4">
        <p>Loading debug data...</p>
      </Container>
    );
  }

  return (
    <Container className="mt-4">
      <h2 className="mb-4">🔍 Debug Dashboard</h2>

      <Alert variant="info" className="mb-4">
        <strong>Database Access:</strong> View all stored user data, meals, and food database
      </Alert>

      <Tabs defaultActiveKey="users" className="mb-4">
        <Tab eventKey="users" title="Users & Profiles">
          {allData && (
            <Card>
              <Card.Header>
                <h5>Users ({Object.keys(allData.users || {}).length})</h5>
              </Card.Header>
              <Card.Body style={{ maxHeight: '400px', overflowY: 'auto' }}>
                <Table striped bordered hover size="sm">
                  <thead>
                    <tr>
                      <th>Email</th>
                      <th>Name</th>
                      <th>Age</th>
                      <th>Weight</th>
                      <th>Height</th>
                      <th>Activity</th>
                      <th>Goal</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(allData.user_profiles || {}).map(([uid, profile]) => (
                      <tr key={uid}>
                        <td>{profile.email}</td>
                        <td>{profile.name}</td>
                        <td>{profile.age}</td>
                        <td>{profile.weight || '—'}</td>
                        <td>{profile.height || '—'}</td>
                        <td>{profile.activity_level || '—'}</td>
                        <td>{profile.goal || '—'}</td>
                      </tr>
                    ))}
                  </tbody>
                </Table>
              </Card.Body>
              <div className="text-center mt-3">
                <Button 
                  variant="primary" 
                  onClick={() => downloadData(allData.user_profiles, 'user_profiles.json')}
                >
                  📥 Download User Profiles
                </Button>
              </div>
            </Card>
          )}
        </Tab>

        <Tab eventKey="meals" title="Meal Logs">
          {allData && (
            <Card>
              <Card.Header>
                <h5>User Meal Logs</h5>
              </Card.Header>
              <Card.Body style={{ maxHeight: '400px', overflowY: 'auto' }}>
                <Table striped bordered hover size="sm">
                  <thead>
                    <tr>
                      <th>User ID</th>
                      <th>Total Meals</th>
                      <th>Sample Meals</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(allData.user_logs || {}).map(([uid, logs]) => (
                      <tr key={uid}>
                        <td>{uid}</td>
                        <td>{logs.diet_logs?.length || 0}</td>
                        <td>
                          {logs.diet_logs?.slice(0, 3).map((meal, i) => (
                            <div key={i} className="small">
                              {meal.food_name} ({meal.calories} cal)
                            </div>
                          ))}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </Table>
              </Card.Body>
            </Card>
          )}
        </Tab>

        <Tab eventKey="foods" title="Food Database">
          {foodData && (
            <Card>
              <Card.Header>
                <h5>Food Database ({foodData.total_foods} foods)</h5>
              </Card.Header>
              <Card.Body style={{ maxHeight: '400px', overflowY: 'auto' }}>
                <Table striped bordered hover size="sm">
                  <thead>
                    <tr>
                      <th>Food Name</th>
                      <th>Calories (per 100g)</th>
                      <th>Protein (g)</th>
                      <th>Carbs (g)</th>
                      <th>Fats (g)</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(foodData.food_database || {}).map(([name, nutrition]) => (
                      <tr key={name}>
                        <td>{name.charAt(0).toUpperCase() + name.slice(1)}</td>
                        <td>{nutrition.calories}</td>
                        <td>{nutrition.protein}</td>
                        <td>{nutrition.carbs}</td>
                        <td>{nutrition.fats}</td>
                      </tr>
                    ))}
                  </tbody>
                </Table>
              </Card.Body>
              <div className="text-center mt-3">
                <Button 
                  variant="success" 
                  onClick={() => downloadData(foodData.food_database, 'food_database.json')}
                >
                  📥 Download Food Database
                </Button>
              </div>
            </Card>
          )}
        </Tab>
      </Tabs>
    </Container>
  );
};

export default DebugDashboard;
